        this->definition = definition;
        left = right = nullptr;
    }
};
```

### **2.2. BST Class**

```cpp
class BST {
private:
    Node* root;

    // Helper functions
    Node* insertNode(Node* node, const std::string& word, const std::string& definition);
    Node* searchNode(Node* node, const std::string& word);
    Node* findMin(Node* node);
    Node* deleteNode(Node* node, const std::string& word);
    void inOrderTraversal(Node* node);

public:
    BST() : root(nullptr) {}

    void insert(const std::string& word, const std::string& definition);
    void search(const std::string& word);
    void deleteWord(const std::string& word);
    void printDictionary();
};
```

### **2.3. Implementation of BST Functions**

```cpp
// Insert a word and definition into the BST
void BST::insert(const std::string& word, const std::string& definition) {
    root = insertNode(root, word, definition);
}

Node* BST::insertNode(Node* node, const std::string& word, const std::string& definition) {
    if (node == nullptr) {
        return new Node(word, definition);
    }

    if (word < node->word) {
        node->left = insertNode(node->left, word, definition);
    } else if (word > node->word) {
        node->right = insertNode(node->right, word, definition);
    } else {
        // Word already exists
        node->definition = definition;
    }

    return node;
}

// Search for a word in the BST
void BST::search(const std::string& word) {
    Node* node = searchNode(root, word);
    if (node == nullptr) {
        std::cout << "Word not found in the dictionary.\n";
    } else {
        std::cout << "Definition of \"" << word << "\": " << node->definition << "\n";
    }
}

Node* BST::searchNode(Node* node, const std::string& word) {
    if (node == nullptr) {
        return nullptr;
    }

    if (word == node->word) {
        return node;
    } else if (word < node->word) {
        return searchNode(node->left, word);
    } else {
        return searchNode(node->right, word);
    }
}

// Delete a word from the BST
void BST::deleteWord(const std::string& word) {
    root = deleteNode(root, word);
}

Node* BST::deleteNode(Node* node, const std::string& word) {
    if (node == nullptr) {
        return nullptr;
    }

    if (word < node->word) {
        node->left = deleteNode(node->left, word);
    } else if (word > node->word) {
        node->right = deleteNode(node->right, word);
    } else {
        // Node with only one child or no child
        if (node->left == nullptr) {
            Node* temp = node->right;
            delete node;
            return temp;
        } else if (node->right == nullptr) {
            Node* temp = node->left;
            delete node;
            return temp;
        } else {
            // Node with two children: Get the inorder successor (smallest in right subtree)
            Node* temp = findMin(node->right);
            // Copy the inorder successor's content to this node
            node->word = temp->word;
            node->definition = temp->definition;
            // Delete the inorder successor
            node->right = deleteNode(node->right, temp->word);
        }
    }
    return node;
}

// Print all words in the BST in sorted order
void BST::printDictionary() {
    std::cout << "\n=== Dictionary ===\n";
    inOrderTraversal(root);
    std::cout << "===================\n";
}

void BST::inOrderTraversal(Node* node) {
    if (node == nullptr) {
        return;
    }

    inOrderTraversal(node->left);
    std::cout << "Word: " << node->word << ", Definition: " << node->definition << "\n";
    inOrderTraversal(node->right);
}
